import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.Cqf6AMW8.js";const u=JSON.parse('{"title":"SQL 数据库","description":"SQL 数据库的基础知识，包括SQL语法、数据库分类和SQLite存储等。","frontmatter":{"title":"SQL 数据库","description":"SQL 数据库的基础知识，包括SQL语法、数据库分类和SQLite存储等。","date":"2026-04-21T00:00:00.000Z","tags":["SQL","数据库","SQLite"],"sidebar":"auto"},"headers":[],"relativePath":"docs/data/ds-6-SQL.md","filePath":"docs/data/ds-6-SQL.md","lastUpdated":1776715536000}'),l={name:"docs/data/ds-6-SQL.md"};function o(i,t,h,s,n,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="sql" tabindex="-1">SQL <a class="header-anchor" href="#sql" aria-label="Permalink to &quot;SQL&quot;">​</a></h1><h2 id="_1-sql基础" tabindex="-1">1. SQL基础 <a class="header-anchor" href="#_1-sql基础" aria-label="Permalink to &quot;1. SQL基础&quot;">​</a></h2><h3 id="_1-1-mysql指令" tabindex="-1">1.1 MySQL指令 <a class="header-anchor" href="#_1-1-mysql指令" aria-label="Permalink to &quot;1.1 MySQL指令&quot;">​</a></h3><ul><li><strong>show databases</strong>：查看有哪些数据库</li><li><strong>use dbid</strong>：进入该数据库</li><li><strong>show tables</strong>：查看该数据库有哪些表</li><li><strong>exit</strong>：退出MySQL</li></ul><h3 id="_1-2-sql基础语法" tabindex="-1">1.2 SQL基础语法 <a class="header-anchor" href="#_1-2-sql基础语法" aria-label="Permalink to &quot;1.2 SQL基础语法&quot;">​</a></h3><h4 id="_1-2-1-ddl-定义语法" tabindex="-1">1.2.1 DDL(定义语法) <a class="header-anchor" href="#_1-2-1-ddl-定义语法" aria-label="Permalink to &quot;1.2.1 DDL(定义语法)&quot;">​</a></h4><h5 id="库语言" tabindex="-1">库语言 <a class="header-anchor" href="#库语言" aria-label="Permalink to &quot;库语言&quot;">​</a></h5><ul><li><strong>show databases</strong>：查看有哪些数据库</li><li><strong>use dbid</strong>：进入目标数据库</li><li><strong>create database dbid</strong>：创建新的数据库</li><li><strong>select database</strong>：查看当前数据库</li></ul><h5 id="表语言" tabindex="-1">表语言 <a class="header-anchor" href="#表语言" aria-label="Permalink to &quot;表语言&quot;">​</a></h5><ul><li><strong>show tables</strong>：查看表格</li><li><strong>create table tableid (listid1 类型，……)</strong>：创建新表格</li><li><strong>drop table tableid</strong>：删除表格</li></ul><h4 id="_1-2-2-dml-操作语法" tabindex="-1">1.2.2 DML(操作语法) <a class="header-anchor" href="#_1-2-2-dml-操作语法" aria-label="Permalink to &quot;1.2.2 DML(操作语法)&quot;">​</a></h4><ul><li><strong>insert into tableid [(list1，list2，list3……)] value(值1，值2，值3……)</strong>：插值</li><li><strong>delete from tableid (while判断)</strong>：去值</li><li><strong>update tableid set list=value(while条件)</strong>：更新</li></ul><h4 id="_1-2-3-dql-查询语法" tabindex="-1">1.2.3 DQL(查询语法) <a class="header-anchor" href="#_1-2-3-dql-查询语法" aria-label="Permalink to &quot;1.2.3 DQL(查询语法)&quot;">​</a></h4><ul><li><strong>select listid from tableid(while 条件)</strong>：查询id列表</li><li><strong>select * from tableid</strong>：查询所有列表</li><li><strong>select listid|count_def from tableid(while 条件) group by listid</strong>：查询id列表/聚合函数</li><li><strong>后缀：+order by listid[asc/desc]</strong>：asc表示正向排序/desc表示反向排序</li></ul><h3 id="_1-3-pymysql" tabindex="-1">1.3 pymysql <a class="header-anchor" href="#_1-3-pymysql" aria-label="Permalink to &quot;1.3 pymysql&quot;">​</a></h3><ul><li><strong>pymysql</strong>：python管理数据库的包</li></ul><h3 id="_1-4-备注" tabindex="-1">1.4 备注 <a class="header-anchor" href="#_1-4-备注" aria-label="Permalink to &quot;1.4 备注&quot;">​</a></h3><h4 id="_1-4-1-术语说明" tabindex="-1">1.4.1 术语说明 <a class="header-anchor" href="#_1-4-1-术语说明" aria-label="Permalink to &quot;1.4.1 术语说明&quot;">​</a></h4><ul><li><strong>dbid</strong>：数据库名</li><li><strong>tableid</strong>：表格名</li><li><strong>listid</strong>：列名</li></ul><h4 id="_1-4-2-数据类型" tabindex="-1">1.4.2 数据类型 <a class="header-anchor" href="#_1-4-2-数据类型" aria-label="Permalink to &quot;1.4.2 数据类型&quot;">​</a></h4><ul><li><strong>整形</strong>：int</li><li><strong>浮点</strong>：float</li><li><strong>字符</strong>：varchar(最长255)</li><li><strong>日期</strong>：data</li><li><strong>时间</strong>：timestamp</li></ul><h4 id="_1-4-3-聚合函数" tabindex="-1">1.4.3 聚合函数 <a class="header-anchor" href="#_1-4-3-聚合函数" aria-label="Permalink to &quot;1.4.3 聚合函数&quot;">​</a></h4><ul><li><strong>sum（列）</strong>：求和</li><li><strong>avg（列）</strong>：均值</li><li><strong>min（列）</strong>：最小</li><li><strong>max（列）</strong>：最大</li><li><strong>const（列）</strong>：求数量</li></ul><h2 id="_2-数据库分类" tabindex="-1">2. 数据库分类 <a class="header-anchor" href="#_2-数据库分类" aria-label="Permalink to &quot;2. 数据库分类&quot;">​</a></h2><h3 id="_2-1-常见数据库分类" tabindex="-1">2.1 常见数据库分类 <a class="header-anchor" href="#_2-1-常见数据库分类" aria-label="Permalink to &quot;2.1 常见数据库分类&quot;">​</a></h3><ul><li>一般情况下：MySQL+Redis够用</li><li>小型项目：SQL</li></ul><h3 id="_2-2-关系型数据库-rdbms" tabindex="-1">2.2 关系型数据库 (RDBMS) <a class="header-anchor" href="#_2-2-关系型数据库-rdbms" aria-label="Permalink to &quot;2.2 关系型数据库 (RDBMS)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>数据库名称</th><th>开发商</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td>MySQL</td><td>Oracle</td><td>开源、稳定、性能优异</td><td>网站、应用后端、中小型系统</td></tr><tr><td>PostgreSQL</td><td>PostgreSQL Global Development Group</td><td>功能丰富、支持复杂查询、扩展性强</td><td>企业级应用、数据分析、GIS系统</td></tr><tr><td>Oracle Database</td><td>Oracle</td><td>功能全面、可靠性高、适合大型系统</td><td>大型企业、金融、政府系统</td></tr><tr><td>SQL Server</td><td>Microsoft</td><td>与Windows生态集成、管理工具友好</td><td>企业内部系统、.NET应用</td></tr><tr><td>SQLite</td><td>D. Richard Hipp</td><td>轻量级、文件型数据库、无需服务器</td><td>移动应用、嵌入式系统、小型工具</td></tr><tr><td>MariaDB</td><td>MariaDB Foundation</td><td>MySQL分支、开源、性能优化</td><td>替代MySQL的场景、开源项目</td></tr></tbody></table><h3 id="_2-3-非关系型数据库-nosql" tabindex="-1">2.3 非关系型数据库 (NoSQL) <a class="header-anchor" href="#_2-3-非关系型数据库-nosql" aria-label="Permalink to &quot;2.3 非关系型数据库 (NoSQL)&quot;">​</a></h3><h4 id="_2-3-1-文档型数据库" tabindex="-1">2.3.1 文档型数据库 <a class="header-anchor" href="#_2-3-1-文档型数据库" aria-label="Permalink to &quot;2.3.1 文档型数据库&quot;">​</a></h4><table tabindex="0"><thead><tr><th>数据库名称</th><th>开发商</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td>MongoDB</td><td>MongoDB Inc.</td><td>文档存储、灵活模式、水平扩展</td><td>内容管理、用户数据、移动应用后端</td></tr><tr><td>CouchDB</td><td>Apache Software Foundation</td><td>面向文档、RESTful API、支持复制</td><td>离线应用、移动同步、内容管理</td></tr><tr><td>RavenDB</td><td>Hibernating Rhinos</td><td>面向文档、ACID事务、内置全文搜索</td><td>.NET应用、企业级文档存储</td></tr></tbody></table><h4 id="_2-3-2-键值存储数据库" tabindex="-1">2.3.2 键值存储数据库 <a class="header-anchor" href="#_2-3-2-键值存储数据库" aria-label="Permalink to &quot;2.3.2 键值存储数据库&quot;">​</a></h4><table tabindex="0"><thead><tr><th>数据库名称</th><th>开发商</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td>Redis</td><td>Redis Labs</td><td>内存存储、高性能、支持多种数据结构</td><td>缓存、会话存储、实时分析</td></tr><tr><td>Memcached</td><td>Danga Interactive</td><td>简单键值存储、高性能、分布式</td><td>缓存、会话管理、高频读写场景</td></tr><tr><td>DynamoDB</td><td>Amazon</td><td>完全托管、高可用、自动扩展</td><td>云原生应用、服务器less架构</td></tr></tbody></table><h4 id="_2-3-3-列存储数据库" tabindex="-1">2.3.3 列存储数据库 <a class="header-anchor" href="#_2-3-3-列存储数据库" aria-label="Permalink to &quot;2.3.3 列存储数据库&quot;">​</a></h4><table tabindex="0"><thead><tr><th>数据库名称</th><th>开发商</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td>Cassandra</td><td>Apache Software Foundation</td><td>高可扩展、分布式、容错</td><td>大数据、物联网、时间序列数据</td></tr><tr><td>HBase</td><td>Apache Software Foundation</td><td>基于Hadoop、高可靠性、列式存储</td><td>大数据、实时查询、结构化数据</td></tr><tr><td>ClickHouse</td><td>Yandex</td><td>列式存储、OLAP优化、高性能分析</td><td>数据分析、BI系统、日志分析</td></tr></tbody></table><h4 id="_2-3-4-图数据库" tabindex="-1">2.3.4 图数据库 <a class="header-anchor" href="#_2-3-4-图数据库" aria-label="Permalink to &quot;2.3.4 图数据库&quot;">​</a></h4><table tabindex="0"><thead><tr><th>数据库名称</th><th>开发商</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td>Neo4j</td><td>Neo4j, Inc.</td><td>原生图存储、Cypher查询语言</td><td>社交网络、推荐系统、知识图谱</td></tr><tr><td>OrientDB</td><td>OrientDB LTD</td><td>多模型数据库、支持图和文档</td><td>复杂关系、实时分析、混合数据</td></tr><tr><td>ArangoDB</td><td>ArangoDB GmbH</td><td>多模型数据库、AQL查询语言</td><td>复杂数据关系、实时应用</td></tr></tbody></table><h3 id="_2-4-内存数据库" tabindex="-1">2.4 内存数据库 <a class="header-anchor" href="#_2-4-内存数据库" aria-label="Permalink to &quot;2.4 内存数据库&quot;">​</a></h3><table tabindex="0"><thead><tr><th>数据库名称</th><th>开发商</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td>Redis</td><td>Redis Labs</td><td>内存存储、多种数据结构、持久化</td><td>缓存、会话管理、实时分析</td></tr><tr><td>Memcached</td><td>Danga Interactive</td><td>简单键值存储、高性能</td><td>缓存、会话存储</td></tr><tr><td>SAP HANA</td><td>SAP</td><td>内存计算、OLAP和OLTP混合</td><td>企业级分析、实时决策</td></tr><tr><td>VoltDB</td><td>VoltDB Inc.</td><td>内存OLTP、ACID事务</td><td>金融交易、电信计费、实时监控</td></tr></tbody></table><h3 id="_2-5-时序数据库" tabindex="-1">2.5 时序数据库 <a class="header-anchor" href="#_2-5-时序数据库" aria-label="Permalink to &quot;2.5 时序数据库&quot;">​</a></h3><table tabindex="0"><thead><tr><th>数据库名称</th><th>开发商</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td>InfluxDB</td><td>InfluxData</td><td>时间序列优化、高性能写入</td><td>IoT传感器数据、监控系统、日志分析</td></tr><tr><td>Prometheus</td><td>CNCF</td><td>开源监控系统、时序数据存储</td><td>系统监控、告警、指标收集</td></tr><tr><td>TimescaleDB</td><td>Timescale</td><td>PostgreSQL扩展、关系型时序数据库</td><td>时间序列数据、分析查询</td></tr><tr><td>OpenTSDB</td><td>OpenTSDB Community</td><td>基于HBase、大规模时序数据</td><td>监控系统、物联网数据</td></tr></tbody></table><h3 id="_2-6-搜索引擎数据库" tabindex="-1">2.6 搜索引擎数据库 <a class="header-anchor" href="#_2-6-搜索引擎数据库" aria-label="Permalink to &quot;2.6 搜索引擎数据库&quot;">​</a></h3><table tabindex="0"><thead><tr><th>数据库名称</th><th>开发商</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td>Elasticsearch</td><td>Elastic</td><td>分布式搜索、全文索引、实时分析</td><td>全文搜索、日志分析、监控告警</td></tr><tr><td>Solr</td><td>Apache Software Foundation</td><td>企业级搜索、可扩展性强</td><td>网站搜索、电子商务、内容管理</td></tr><tr><td>Sphinx</td><td>Sphinx Technologies Inc.</td><td>全文搜索、高性能、开源</td><td>网站搜索、应用内搜索</td></tr><tr><td>Algolia</td><td>Algolia</td><td>托管搜索服务、实时搜索</td><td>前端搜索、电商产品搜索</td></tr></tbody></table><h2 id="_3-sqlite存储" tabindex="-1">3. SQLite存储 <a class="header-anchor" href="#_3-sqlite存储" aria-label="Permalink to &quot;3. SQLite存储&quot;">​</a></h2><h3 id="_3-1-sqlite数据类型" tabindex="-1">3.1 SQLite数据类型 <a class="header-anchor" href="#_3-1-sqlite数据类型" aria-label="Permalink to &quot;3.1 SQLite数据类型&quot;">​</a></h3><p>SQLite 采用动态类型系统，支持以下主要数据类型：</p><table tabindex="0"><thead><tr><th>数据类型</th><th>描述</th><th>存储文件的应用</th></tr></thead><tbody><tr><td>null</td><td>空值</td><td>表示不存在的数据</td></tr><tr><td>integer</td><td>整数类型（1-8字节）</td><td>存储文件大小、ID等数值信息</td></tr><tr><td>real</td><td>浮点数类型（8字节）</td><td>存储文件相关的浮点数值</td></tr><tr><td>text</td><td>文本类型（UTF-8/UTF-16）</td><td>存储文件路径、文件名、描述等文本信息</td></tr><tr><td>blob</td><td>二进制大对象</td><td><strong>直接存储文件的二进制数据</strong>，如图片、音频、视频等</td></tr></tbody></table><h3 id="_3-2-适合存储的文件类型" tabindex="-1">3.2 适合存储的文件类型 <a class="header-anchor" href="#_3-2-适合存储的文件类型" aria-label="Permalink to &quot;3.2 适合存储的文件类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件类型</th><th>建议存储方式</th><th>适用场景</th></tr></thead><tbody><tr><td>文本文件（.txt, .csv等）</td><td>text 或 blob</td><td>小文本文件适合text，大文本文件适合blob</td></tr><tr><td>图片文件（.jpg, .png等）</td><td>blob 或路径存储</td><td>小图片适合blob，大图片建议路径存储</td></tr><tr><td>音频文件（.mp3, .wav等）</td><td>blob 或路径存储</td><td>短音效适合blob，音乐文件建议路径存储</td></tr><tr><td>视频文件（.mp4, .avi等）</td><td>路径存储</td><td>视频文件通常较大，建议存储路径</td></tr><tr><td>文档文件（.pdf, .doc等）</td><td>blob 或路径存储</td><td>小文档适合blob，大文档建议路径存储</td></tr><tr><td>配置文件（.json, .xml等）</td><td>text 或 blob</td><td>适合text存储，方便直接读取和修改</td></tr></tbody></table><h3 id="_3-3-存储策略" tabindex="-1">3.3 存储策略 <a class="header-anchor" href="#_3-3-存储策略" aria-label="Permalink to &quot;3.3 存储策略&quot;">​</a></h3><table tabindex="0"><thead><tr><th>策略</th><th>适用场景</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>全部blob存储</td><td>小文件、数据完整性要求高</td><td>数据一致性好，备份简单</td><td>数据库文件大，性能可能下降</td></tr><tr><td>全部路径存储</td><td>大文件、性能要求高</td><td>数据库小，性能好</td><td>数据完整性依赖文件系统</td></tr><tr><td>混合存储</td><td>混合大小的文件</td><td>灵活适应不同场景</td><td>管理复杂度增加</td></tr></tbody></table>',51)])])}const g=d(l,[["render",o]]);export{u as __pageData,g as default};
